            return total_cost;
        }

        // Move to the next cell (right or down) if time is odd
        if (time % 2 == 1) {
            for (auto& dir : directions) {
                long long ni = i + dir.first;
                long long nj = j + dir.second;

                // Check if the new cell is within bounds
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long long new_time = time + 1;
                    long long new_cost = total_cost + (ni + 1) * (nj + 1);

                    // Update the DP table if this path is better
                    if (new_cost < dp[ni][nj]) {
                        dp[ni][nj] = new_cost;
                        pq.push({new_cost, new_time, ni, nj});
                    }
                }
            }
        } 
        // Wait if time is even
        else {
            long long new_time = time + 1;
            long long new_cost = total_cost + waitCost[i][j];

